@namespace CheckoutWizard

<fieldset>
    <div class="form-group">
        <label for="card">Card Number</label>
        <input id="card" @bind="Payment.CardNumber" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="expiry">Expiry Date</label>
        <input id="expiry" placeholder="MM/YY" @bind="Payment.ExpiryDate" @bind:event="oninput" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error" role="alert">@_errorMessage</div>
}

<div class="button-group">
    <button class="btn-back" @onclick="OnBack">Back</button>

    <button class="btn-place-order" @onclick="HandlePlaceOrderAsync">
        Place Order
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback OnPlaceOrder { get; set; }

    private string? _errorMessage;

    private async Task HandlePlaceOrderAsync()
    {
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(Payment.CardNumber)
            || string.IsNullOrWhiteSpace(Payment.ExpiryDate))
        {
            _errorMessage = "Card number and expiry date are required.";
            return;
        }

        await OnPlaceOrder.InvokeAsync();
    }
}
